// Seed function
async function seedProducts() {
  try {
    await Product.deleteMany({}); // remove old products
    const created = await Product.insertMany(products);
    console.log(`✅ ${created.length} products added`);
    mongoose.disconnect();
  } catch (err) {
    console.error("Error seeding products:", err);
  }
}

// Run seed
seedProducts();
